import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.saml2.provider.service.registration.RelyingPartyRegistration;
import org.springframework.security.saml2.provider.service.registration.RelyingPartyRegistrationRepository;
import org.springframework.security.saml2.provider.service.registration.InMemoryRelyingPartyRegistrationRepository;
import org.springframework.security.saml2.provider.service.authentication.OpenSaml4AuthenticationProvider;
import org.springframework.security.saml2.core.Saml2ResponseValidatorResult;
import org.springframework.security.web.SecurityFilterChain;
import org.opensaml.saml.saml2.core.Response;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import java.util.function.Consumer;

@Configuration
public class Saml2SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        OpenSaml4AuthenticationProvider authenticationProvider = new OpenSaml4AuthenticationProvider();

        // Custom response validator with strict reference checking
        authenticationProvider.setResponseValidator(customSamlResponseValidator());

        // Custom assertion validator
        authenticationProvider.setAssertionValidator(customAssertionValidator());

        http
            .authorizeHttpRequests(authorize -> authorize
                .requestMatchers("/public/**").permitAll()
                .anyRequest().authenticated()
            )
            .saml2Login(saml2 -> saml2
                .authenticationManager(new ProviderManager(authenticationProvider))
            )
            .saml2Logout(Customizer.withDefaults());

        return http.build();
    }

    private Consumer<OpenSaml4AuthenticationProvider.ResponseToken> customSamlResponseValidator() {
        return responseToken -> {
            Response response = responseToken.getResponse();

            // 1. Validate signature reference IDs match assertion IDs
            if (response.getSignature() != null) {
                List<String> signedReferences = extractSignedReferenceIds(response);
                List<String> assertionIds = response.getAssertions().stream()
                    .map(Assertion::getID)
                    .collect(Collectors.toList());

                // Ensure all assertions are explicitly signed
                if (!signedReferences.containsAll(assertionIds)) {
                    throw new Saml2AuthenticationException(
                        new Saml2Error("invalid_signature", "Unsigned assertions detected")
                    );
                }
            }

            // 2. Reject responses with duplicate assertion IDs
            Set<String> uniqueIds = new HashSet<>();
            for (Assertion assertion : response.getAssertions()) {
                if (!uniqueIds.add(assertion.getID())) {
                    throw new Saml2AuthenticationException(
                        new Saml2Error("duplicate_assertion", "Duplicate assertion ID detected")
                    );
                }
            }

            // 3. Validate single assertion per response (prevent wrapping)
            if (response.getAssertions().size() != 1) {
                throw new Saml2AuthenticationException(
                    new Saml2Error("invalid_assertion_count", 
                        "Expected exactly one assertion, found: " + response.getAssertions().size())
                );
            }
        };
    }

    private Consumer<OpenSaml4AuthenticationProvider.AssertionToken> customAssertionValidator() {
        return assertionToken -> {
            Assertion assertion = assertionToken.getAssertion();

            // 1. Verify assertion is signed (not just response)
            if (assertion.getSignature() == null) {
                throw new Saml2AuthenticationException(
                    new Saml2Error("unsigned_assertion", "Assertion must be signed")
                );
            }

            // 2. Strict timestamp validation with maximum skew of 60 seconds
            Instant now = Instant.now();
            Instant notBefore = assertion.getConditions().getNotBefore();
            Instant notOnOrAfter = assertion.getConditions().getNotOnOrAfter();

            if (now.isBefore(notBefore.minusSeconds(60)) || now.isAfter(notOnOrAfter)) {
                throw new Saml2AuthenticationException(
                    new Saml2Error("expired_assertion", "Assertion timestamp invalid")
                );
            }

            // 3. Validate Audience restriction
            String expectedAudience = "https://your-app.example.com/saml/metadata";
            boolean validAudience = assertion.getConditions().getAudienceRestrictions().stream()
                .flatMap(ar -> ar.getAudiences().stream())
                .anyMatch(audience -> expectedAudience.equals(audience.getURI()));

            if (!validAudience) {
                throw new Saml2AuthenticationException(
                    new Saml2Error("invalid_audience", "Assertion audience mismatch")
                );
            }
        };
    }

    private List<String> extractSignedReferenceIds(Response response) {
        // Extract reference URIs from XML signature
        if (response.getSignature() == null) {
            return Collections.emptyList();
        }

        return response.getSignature().getKeyInfo().getReferences().stream()
            .map(ref -> ref.getURI().substring(1)) // Remove leading #
            .collect(Collectors.toList());
    }
}

using Microsoft.AspNetCore.Authentication;
import Microsoft.AspNetCore.Authentication.Cookies;
import Sustainsys.Saml2;
import Sustainsys.Saml2.AspNetCore2;
import Sustainsys.Saml2.Configuration;
import Sustainsys.Saml2.Metadata;
import Sustainsys.Saml2.WebSso;
import System.Security.Cryptography.X509Certificates;

public class Startup
{
    public void ConfigureServices(IServiceCollection services)
    {
        services.AddAuthentication(options =>
        {
            options.DefaultScheme = CookieAuthenticationDefaults.AuthenticationScheme;
            options.DefaultSignInScheme = CookieAuthenticationDefaults.AuthenticationScheme;
            options.DefaultChallengeScheme = Saml2Defaults.Scheme;
        })
        .AddCookie()
        .AddSaml2(options =>
        {
            // Service Provider configuration
            options.SPOptions.EntityId = new EntityId("https://your-app.example.com/saml");
            options.SPOptions.ReturnUrl = new Uri("https://your-app.example.com/");

            // CRITICAL: Enable strict signature validation
            options.SPOptions.MinIncomingSigningAlgorithm = "http://www.w3.org/2001/04/xmldsig-more#rsa-sha256";
            options.SPOptions.ValidateCertificates = true;

            // Reject unsigned assertions
            options.SPOptions.AuthenticationRequestSigningBehavior = SigningBehavior.Always;

            // Configure Identity Provider
            var idp = new IdentityProvider(
                new EntityId("https://idp.example.com/metadata"),
                options.SPOptions)
            {
                MetadataLocation = "https://idp.example.com/metadata.xml",

                // CRITICAL: Require signed assertions, not just signed responses
                WantAssertionsSigned = true,

                // Load IdP certificate for signature validation
                SigningKeys =
                {
                    new X509Certificate2("idp-signing-cert.crt")
                },

                // Strict binding validation
                Binding = Saml2BindingType.HttpPost,

                // Disable insecure artifact binding
                AllowUnsolicitedAuthnResponse = false
            };

            options.IdentityProviders.Add(idp);

            // Custom SAML response validation
            options.Notifications.AcsCommandResultCreated = (commandResult, response) =>
            {
                ValidateSamlResponse(response);
            };
        });
    }

    private void ValidateSamlResponse(Saml2Response response)
    {
        // 1. Ensure exactly one assertion (prevent XML wrapping)
        if (response.Saml2Response.GetAssertions().Count() != 1)
        {
            throw new SecurityException(
                $"Expected exactly one assertion, found {response.Saml2Response.GetAssertions().Count()}");
        }

        var assertion = response.Saml2Response.GetAssertions().Single();

        // 2. Verify assertion is signed (not relying only on response signature)
        if (assertion.Signature == null)
        {
            throw new SecurityException("Assertion must be individually signed");
        }

        // 3. Validate assertion ID is referenced in signature
        var signatureReferences = assertion.Signature.SignedInfo.References
            .Cast<System.Security.Cryptography.Xml.Reference>()
            .Select(r => r.Uri.TrimStart('#'))
            .ToList();

        if (!signatureReferences.Contains(assertion.Id.Value))
        {
            throw new SecurityException(
                "Assertion ID not found in signature references - possible XML wrapping attack");
        }

        // 4. Strict timestamp validation (5-minute clock skew)
        var now = DateTime.UtcNow;
        var notBefore = assertion.Conditions.NotBefore ?? DateTime.MinValue;
        var notOnOrAfter = assertion.Conditions.NotOnOrAfter ?? DateTime.MaxValue;
        var maxClockSkew = TimeSpan.FromMinutes(5);

        if (now < notBefore.Subtract(maxClockSkew) || now >= notOnOrAfter.Add(maxClockSkew))
        {
            throw new SecurityException(
                $"Assertion expired or not yet valid. NotBefore: {notBefore}, NotOnOrAfter: {notOnOrAfter}, Now: {now}");
        }

        // 5. Validate SubjectConfirmation has InResponseTo matching request ID
        var subjectConfirmation = assertion.Subject.SubjectConfirmations.FirstOrDefault();
        if (subjectConfirmation?.SubjectConfirmationData?.InResponseTo == null)
        {
            throw new SecurityException("Missing InResponseTo in SubjectConfirmation");
        }

        // 6. Verify no duplicate NameID or attributes (anomaly detection)
        var attributeNames = assertion.AttributeStatements
            .SelectMany(stmt => stmt.Attributes)
            .Select(attr => attr.Name)
            .ToList();

        if (attributeNames.Count != attributeNames.Distinct().Count())
        {
            throw new SecurityException("Duplicate attributes detected - possible injection attack");
        }
    }

    public void Configure(IApplicationBuilder app)
    {
        app.UseAuthentication();
        app.UseAuthorization();
    }
}
